python3 -c "
import os, re

local_sites = os.path.expanduser('~/Local Sites')
results = []

for site_name in sorted(os.listdir(local_sites)):
    version_file = os.path.join(local_sites, site_name, 'app', 'public', 'wp-includes', 'version.php')
    if os.path.isfile(version_file):
        with open(version_file) as f:
            content = f.read()
        match = re.search(r\"\\\$wp_version = '([^']+)'\", content)
        if match:
            results.append((site_name, match.group(1)))
        else:
            results.append((site_name, 'unknown'))
    else:
        results.append((site_name, 'no-file'))

for name, ver in results:
    print(f'{ver}\t{name}')
"

